// Self-contained HTML proof generator for the Tier-3 evaluator.
//
// Every gate emits one of these: open the file in a browser and you see the
// side-by-side comparison, the diff heatmap, the numeric verdict, and (for
// motion) the embedded clip. No external asset refs — images are inlined as
// data: URIs so the report is reviewable offline and archivable.

import { mkdir, writeFile } from "node:fs/promises";
import { join } from "node:path";

import type { Verdict } from "./thresholds.js";

export type ProofPair = {
  label: string;
  /** Left image (e.g. reconstruction / candidate). */
  a: Buffer;
  aCaption?: string;
  /** Right image (e.g. ground-truth / baseline). */
  b: Buffer;
  bCaption?: string;
  /** Optional pixelmatch heatmap. */
  heatmap?: Buffer;
  pixelDiffPct?: number;
  ssim?: number;
  pass?: boolean;
};

export type ProofMetricRow = { label: string; value: string; pass?: boolean };

export type ProofOptions = {
  title: string;
  /** Directory to write index.html into. Created if absent. */
  outDir: string;
  subtitle?: string;
  verdict?: Verdict;
  pairs?: ProofPair[];
  metrics?: ProofMetricRow[];
  /** Embedded video (mp4/webm) shown inline. */
  video?: { data: Buffer; mime: string };
  /** Frame contact-sheet (e.g. animated render frames). */
  frames?: Buffer[];
  /** Trusted, generator-produced raw HTML/SVG (e.g. a scatter chart). Not escaped. */
  charts?: string[];
  /** Actionable failure detail per the methodology's "detailed issue reporting". */
  failure?: { frameIndex?: number; selector?: string; note?: string };
  /** Footnote — used to carry the provisional-calibration caveat. */
  note?: string;
};

const STYLE = `
:root{color-scheme:light dark}
body{font:14px/1.5 -apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;margin:0;padding:24px;background:#0b0d10;color:#e6e9ef}
h1{font-size:20px;margin:0 0 4px}h2{font-size:15px;margin:28px 0 10px;color:#9aa4b2}
.sub{color:#9aa4b2;margin:0 0 16px}
.verdict{display:inline-block;padding:6px 14px;border-radius:8px;font-weight:600;letter-spacing:.02em}
.pass{background:#0f3d23;color:#5ee08f;border:1px solid #1d6b3f}
.fail{background:#3d0f14;color:#ff7a85;border:1px solid #6b1d27}
table{border-collapse:collapse;width:100%;margin:8px 0}
td,th{border:1px solid #1f2630;padding:8px 10px;text-align:left;vertical-align:top}
th{color:#9aa4b2;font-weight:600}
.grid{display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;margin:10px 0}
.cell{border:1px solid #1f2630;border-radius:8px;padding:8px;background:#11151b}
.cell h3{margin:0 0 6px;font-size:12px;color:#9aa4b2;font-weight:600}
img{max-width:100%;height:auto;display:block;border-radius:4px;background:#000}
.contact{display:flex;flex-wrap:wrap;gap:4px}.contact img{width:120px}
video{max-width:100%;border-radius:8px;background:#000}
.m{font-variant-numeric:tabular-nums}
.ok{color:#5ee08f}.no{color:#ff7a85}
.note{color:#6b7686;font-size:12px;margin-top:24px;border-top:1px solid #1f2630;padding-top:12px}
.fail-box{background:#1a0e10;border:1px solid #6b1d27;border-radius:8px;padding:12px;margin:10px 0}
`;

const escape = (s: string): string =>
  s.replace(/[&<>"]/g, (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;" })[c]!);

const dataUri = (buffer: Buffer, mime = "image/png"): string =>
  `data:${mime};base64,${buffer.toString("base64")}`;

function pairBlock(pair: ProofPair): string {
  const metric =
    pair.pixelDiffPct === undefined && pair.ssim === undefined
      ? ""
      : `<p class="m">pixelDiff <b class="${pair.pass === false ? "no" : "ok"}">${pair.pixelDiffPct ?? "—"}%</b>` +
        ` &nbsp; SSIM <b>${pair.ssim ?? "—"}</b>` +
        (pair.pass === undefined ? "" : ` &nbsp; ${pair.pass ? '<span class="ok">PASS</span>' : '<span class="no">FAIL</span>'}`) +
        `</p>`;
  const heatmapCell = pair.heatmap
    ? `<div class="cell"><h3>diff heatmap</h3><img src="${dataUri(pair.heatmap)}"/></div>`
    : "";
  return `<h2>${escape(pair.label)}</h2>${metric}<div class="grid">
    <div class="cell"><h3>${escape(pair.aCaption ?? "reconstruction")}</h3><img src="${dataUri(pair.a)}"/></div>
    <div class="cell"><h3>${escape(pair.bCaption ?? "ground truth")}</h3><img src="${dataUri(pair.b)}"/></div>
    ${heatmapCell}
  </div>`;
}

export function renderProofHtml(opts: ProofOptions): string {
  const parts: string[] = [];
  parts.push(`<h1>${escape(opts.title)}</h1>`);
  if (opts.subtitle) parts.push(`<p class="sub">${escape(opts.subtitle)}</p>`);
  if (opts.verdict) {
    const v = opts.verdict;
    parts.push(
      `<span class="verdict ${v.pass ? "pass" : "fail"}">${v.pass ? "INDISTINGUISHABLE" : "DISTINGUISHABLE"}` +
        ` — pixelDiff ${v.pixelDiffPct}% (max ${v.thresholds.pixelDiffMax}%), SSIM ${v.ssim} (min ${v.thresholds.ssimMin}), via ${v.reason}</span>`,
    );
  }
  if (opts.failure) {
    const f = opts.failure;
    parts.push(
      `<div class="fail-box"><b>Failure detail.</b> ` +
        [
          f.frameIndex !== undefined ? `frame #${f.frameIndex}` : "",
          f.selector ? `selector <code>${escape(f.selector)}</code>` : "",
          f.note ? escape(f.note) : "",
        ]
          .filter(Boolean)
          .join(" · ") +
        `</div>`,
    );
  }
  if (opts.metrics?.length) {
    parts.push(
      `<h2>metrics</h2><table><tr><th>metric</th><th>value</th></tr>` +
        opts.metrics
          .map(
            (m) =>
              `<tr><td>${escape(m.label)}</td><td class="m ${m.pass === undefined ? "" : m.pass ? "ok" : "no"}">${escape(m.value)}</td></tr>`,
          )
          .join("") +
        `</table>`,
    );
  }
  for (const chart of opts.charts ?? []) parts.push(chart);
  for (const pair of opts.pairs ?? []) parts.push(pairBlock(pair));
  if (opts.video) {
    parts.push(
      `<h2>render</h2><video controls autoplay loop muted src="${dataUri(opts.video.data, opts.video.mime)}"></video>`,
    );
  }
  if (opts.frames?.length) {
    parts.push(
      `<h2>frame contact-sheet (${opts.frames.length})</h2><div class="contact">` +
        opts.frames.map((f) => `<img src="${dataUri(f)}"/>`).join("") +
        `</div>`,
    );
  }
  if (opts.note) parts.push(`<p class="note">${escape(opts.note)}</p>`);

  return `<!doctype html><html><head><meta charset="utf-8"><title>${escape(opts.title)}</title><style>${STYLE}</style></head><body>${parts.join("\n")}</body></html>`;
}

/** Render and write the proof; returns the absolute path to index.html. */
export async function writeProof(opts: ProofOptions): Promise<string> {
  await mkdir(opts.outDir, { recursive: true });
  const htmlPath = join(opts.outDir, "index.html");
  await writeFile(htmlPath, renderProofHtml(opts), "utf8");
  return htmlPath;
}
