#!/usr/bin/env node
// Thin CLI so gates can shell out: `node dist/verify.cjs diff a.png b.png [--out dir]`.
// Exits non-zero on fail so it works as a CI gate.

import { basename, resolve } from "node:path";

import { diffFiles, loadPng } from "./diff.js";
import { PNG } from "pngjs";
import { writeProof } from "./proof.js";
import { verdict } from "./thresholds.js";

function parseArgs(argv: string[]): { positional: string[]; flags: Record<string, string> } {
  const positional: string[] = [];
  const flags: Record<string, string> = {};
  for (let i = 0; i < argv.length; i += 1) {
    const arg = argv[i]!;
    if (arg.startsWith("--")) {
      flags[arg.slice(2)] = argv[i + 1] ?? "";
      i += 1;
    } else {
      positional.push(arg);
    }
  }
  return { positional, flags };
}

async function pngToBuffer(path: string): Promise<Buffer> {
  const img = await loadPng(path);
  const png = new PNG({ width: img.width, height: img.height });
  png.data = Buffer.from(img.data.buffer, img.data.byteOffset, img.data.length);
  return PNG.sync.write(png);
}

async function cmdDiff(positional: string[], flags: Record<string, string>): Promise<number> {
  const [refPath, recPath] = positional;
  if (!refPath || !recPath) {
    console.error("usage: verify diff <reconstruction.png> <ground-truth.png> [--out <dir>]");
    return 2;
  }
  const result = await diffFiles(resolve(recPath), resolve(refPath));
  const v = verdict(result);
  const line =
    `${v.pass ? "PASS" : "FAIL"}  pixelDiff=${result.pixelDiffPct}% ssim=${result.ssim}  -> ` +
    `${v.pass ? "indistinguishable" : "distinguishable"} (gate: <=${v.thresholds.pixelDiffMax}% OR >=${v.thresholds.ssimMin}) [${v.provenance}]`;
  console.log(line);

  if (flags.out) {
    const outDir = resolve(flags.out);
    const [a, b] = await Promise.all([pngToBuffer(resolve(recPath)), pngToBuffer(resolve(refPath))]);
    const htmlPath = await writeProof({
      title: `diff: ${basename(recPath)} vs ${basename(refPath)}`,
      outDir,
      verdict: v,
      pairs: [
        {
          label: "reconstruction vs ground truth",
          a,
          aCaption: basename(recPath),
          b,
          bCaption: basename(refPath),
          heatmap: result.heatmapPng,
          pixelDiffPct: result.pixelDiffPct,
          ssim: result.ssim,
          pass: v.pass,
        },
      ],
      note: `Calibration is provisional: ${v.provenance}.`,
    });
    console.log(`proof: ${htmlPath}`);
  }
  return v.pass ? 0 : 1;
}

async function main(): Promise<number> {
  const [command, ...rest] = process.argv.slice(2);
  const { positional, flags } = parseArgs(rest);
  switch (command) {
    case "diff":
      return cmdDiff(positional, flags);
    default:
      console.error(`unknown command: ${command ?? "(none)"}\nusage: verify diff <a.png> <b.png> [--out <dir>]`);
      return 2;
  }
}

main()
  .then((code) => process.exit(code))
  .catch((error: unknown) => {
    console.error(error instanceof Error ? error.stack : String(error));
    process.exit(2);
  });
